#!/usr/bin/env bash
# Restore Elassandra's schema-aware put-mapping flow in OpenSearch MetadataMappingService.
# The key fix is to collect Cassandra schema mutations during the mapping task and return them
# through ClusterTasksResult so CassandraDiscovery applies them during cluster-state publication.
#
# Usage: ./scripts/patch-opensearch-metadata-mapping-service-elassandra-schema.sh "${OPENSEARCH_CLONE_DIR}"
set -euo pipefail
DEST="${1:?OpenSearch clone root}"
MM="$DEST/server/src/main/java/org/opensearch/cluster/metadata/MetadataMappingService.java"
[[ -f "$MM" ]] || exit 0

python3 - "$MM" <<'PY'
from pathlib import Path
import sys

path = Path(sys.argv[1])
text = path.read_text(encoding="utf-8")

if (
    "builder.build(currentState, schemaUpdate, mutations, events);" in text
    and "ClusterStateTaskConfig.build(Priority.HIGH, request.masterNodeTimeout(), request.schemaUpdate())" in text
    and "org.apache.cassandra.schema.MigrationManager.mergeSchema(" in text
    and "org.elassandra.index.ElasticSecondaryIndex.elasticSecondayIndices.get(" in text
    and "liveIndexService.mapperService().merge(updatedIndexMetadata, MergeReason.MAPPING_UPDATE);" in text
    and "Metadata mappingMetadata = Metadata.builder(currentState.metadata()).put(updatedIndexMetadata, false).build();" in text
):
    print("MetadataMappingService schema-update plumbing already patched:", path)
    raise SystemExit(0)


def replace_once(source: str, old: str, new: str, label: str) -> str:
    if new in source:
        return source
    if old not in source:
        raise SystemExit(f"{path}: anchor not found for {label}")
    return source.replace(old, new, 1)


execute_old = """            Map<Index, MapperService> indexMapperServices = new HashMap<>();\n            ClusterTasksResult.Builder<PutMappingClusterStateUpdateRequest> builder = ClusterTasksResult.builder();\n            try {\n                for (PutMappingClusterStateUpdateRequest request : tasks) {\n                    try {\n                        for (Index index : request.indices()) {\n                            final IndexMetadata indexMetadata = currentState.metadata().getIndexSafe(index);\n                            if (indexMapperServices.containsKey(indexMetadata.getIndex()) == false) {\n                                MapperService mapperService = indicesService.createIndexMapperService(indexMetadata);\n                                indexMapperServices.put(index, mapperService);\n                                // add mappings for all types, we need them for cross-type validation\n                                mapperService.merge(indexMetadata, MergeReason.MAPPING_RECOVERY);\n                            }\n                        }\n                        currentState = applyRequest(currentState, request, indexMapperServices);\n                        builder.success(request);\n                    } catch (Exception e) {\n                        builder.failure(request, e);\n                    }\n                }\n                return builder.build(currentState);\n            } finally {\n                IOUtils.close(indexMapperServices.values());\n            }\n"""

execute_new = """            Map<Index, MapperService> indexMapperServices = new HashMap<>();\n            ClusterTasksResult.Builder<PutMappingClusterStateUpdateRequest> builder = ClusterTasksResult.builder();\n            try {\n                java.util.Collection<org.apache.cassandra.db.Mutation> mutations = new java.util.LinkedList<>();\n                java.util.Collection<org.apache.cassandra.transport.Event.SchemaChange> events = new java.util.LinkedList<>();\n                ClusterStateTaskConfig.SchemaUpdate schemaUpdate = ClusterStateTaskConfig.SchemaUpdate.NO_UPDATE;\n                for (PutMappingClusterStateUpdateRequest request : tasks) {\n                    try {\n                        for (Index index : request.indices()) {\n                            final IndexMetadata indexMetadata = currentState.metadata().getIndexSafe(index);\n                            if (indexMapperServices.containsKey(indexMetadata.getIndex()) == false) {\n                                MapperService mapperService = indicesService.createIndexMapperService(indexMetadata);\n                                indexMapperServices.put(index, mapperService);\n                                // add mappings for all types, we need them for cross-type validation\n                                mapperService.merge(indexMetadata, MergeReason.MAPPING_RECOVERY);\n                            }\n                        }\n                        currentState = applyRequest(currentState, request, indexMapperServices, mutations, events);\n                        builder.success(request);\n                        if (request.schemaUpdate().ordinal() > schemaUpdate.ordinal()) {\n                            schemaUpdate = request.schemaUpdate();\n                        }\n                    } catch (Exception e) {\n                        builder.failure(request, e);\n                    }\n                }\n                return builder.build(currentState, schemaUpdate, mutations, events);\n            } finally {\n                IOUtils.close(indexMapperServices.values());\n            }\n"""

signature_old = """        private ClusterState applyRequest(\n            ClusterState currentState,\n            PutMappingClusterStateUpdateRequest request,\n            Map<Index, MapperService> indexMapperServices\n        ) throws IOException {\n"""

signature_new = """        private ClusterState applyRequest(\n            ClusterState currentState,\n            PutMappingClusterStateUpdateRequest request,\n            Map<Index, MapperService> indexMapperServices,\n            java.util.Collection<org.apache.cassandra.db.Mutation> mutations,\n            java.util.Collection<org.apache.cassandra.transport.Event.SchemaChange> events\n        ) throws IOException {\n"""

original_schema_block = """                builder.put(indexMetadataBuilder);\n                updated |= updatedMapping;\n"""

patched_schema_block = """                builder.put(indexMetadataBuilder);\n                IndexMetadata updatedIndexMetadata = builder.get(index.getName());\n                if (updatedMapping && MapperService.DEFAULT_MAPPING.equals(mergedMapper.type()) == false) {\n                    java.util.List<org.apache.cassandra.db.Mutation> mutations = new java.util.LinkedList<>();\n                    java.util.List<org.apache.cassandra.transport.Event.SchemaChange> events = new java.util.LinkedList<>();\n                    java.util.Map<String, Integer> replication = new java.util.LinkedHashMap<>();\n                    for (String entry : IndexMetadata.INDEX_SETTING_REPLICATION_SETTING.get(updatedIndexMetadata.getSettings())) {\n                        int colon = entry.indexOf(':');\n                        replication.put(entry.substring(0, colon), Integer.parseInt(entry.substring(colon + 1)));\n                    }\n                    org.apache.cassandra.schema.KeyspaceMetadata ksm = clusterService.getSchemaManager().createOrUpdateKeyspace(\n                        updatedIndexMetadata.keyspace(),\n                        updatedIndexMetadata.getNumberOfReplicas() + 1,\n                        replication,\n                        mutations,\n                        events\n                    );\n                    clusterService.getSchemaManager().updateTableSchema(\n                        ksm,\n                        mergedMapper.type(),\n                        java.util.Collections.singletonMap(\n                            updatedIndexMetadata.getIndex(),\n                            org.apache.cassandra.utils.Pair.create(updatedIndexMetadata, mapperService)\n                        ),\n                        mutations,\n                        events\n                    );\n                    if (mutations.isEmpty() == false) {\n                        org.apache.cassandra.schema.MigrationManager.mergeSchema(\n                            mutations,\n                            clusterService.getSchemaManager().getInhibitedSchemaListeners()\n                        );\n                    }\n                }\n                updated |= updatedMapping;\n"""

current_schema_block = """                builder.put(indexMetadataBuilder);\n                IndexMetadata updatedIndexMetadata = builder.get(index.getName());\n                if (updatedMapping && MapperService.DEFAULT_MAPPING.equals(mergedMapper.type()) == false) {\n                    java.util.Map<String, Integer> replication = new java.util.LinkedHashMap<>();\n                    for (String entry : IndexMetadata.INDEX_SETTING_REPLICATION_SETTING.get(updatedIndexMetadata.getSettings())) {\n                        int colon = entry.indexOf(':');\n                        replication.put(entry.substring(0, colon), Integer.parseInt(entry.substring(colon + 1)));\n                    }\n                    org.apache.cassandra.schema.KeyspaceMetadata ksm = clusterService.getSchemaManager().createOrUpdateKeyspace(\n                        updatedIndexMetadata.keyspace(),\n                        updatedIndexMetadata.getNumberOfReplicas() + 1,\n                        replication,\n                        mutations,\n                        events\n                    );\n                    clusterService.getSchemaManager().updateTableSchema(\n                        ksm,\n                        mergedMapper.type(),\n                        java.util.Collections.singletonMap(\n                            updatedIndexMetadata.getIndex(),\n                            org.apache.cassandra.utils.Pair.create(updatedIndexMetadata, mapperService)\n                        ),\n                        mutations,\n                        events\n                    );\n                }\n                updated |= updatedMapping;\n"""

bridge_schema_block = """                builder.put(indexMetadataBuilder);\n                IndexMetadata updatedIndexMetadata = builder.get(index.getName());\n                if (updatedMapping && MapperService.DEFAULT_MAPPING.equals(mergedMapper.type()) == false) {\n                    java.util.Map<String, Integer> replication = new java.util.LinkedHashMap<>();\n                    for (String entry : IndexMetadata.INDEX_SETTING_REPLICATION_SETTING.get(updatedIndexMetadata.getSettings())) {\n                        int colon = entry.indexOf(':');\n                        replication.put(entry.substring(0, colon), Integer.parseInt(entry.substring(colon + 1)));\n                    }\n                    org.apache.cassandra.schema.KeyspaceMetadata ksm = clusterService.getSchemaManager().createOrUpdateKeyspace(\n                        updatedIndexMetadata.keyspace(),\n                        updatedIndexMetadata.getNumberOfReplicas() + 1,\n                        replication,\n                        mutations,\n                        events\n                    );\n                    clusterService.getSchemaManager().updateTableSchema(\n                        ksm,\n                        mergedMapper.type(),\n                        java.util.Collections.singletonMap(\n                            updatedIndexMetadata.getIndex(),\n                            org.apache.cassandra.utils.Pair.create(updatedIndexMetadata, mapperService)\n                        ),\n                        mutations,\n                        events\n                    );\n                    if (mutations.isEmpty() == false) {\n                        org.apache.cassandra.schema.MigrationManager.mergeSchema(\n                            mutations,\n                            clusterService.getSchemaManager().getInhibitedSchemaListeners()\n                        );\n                    }\n                    org.elassandra.index.ElasticSecondaryIndex elasticSecondaryIndex =\n                        org.elassandra.index.ElasticSecondaryIndex.elasticSecondayIndices.get(\n                            updatedIndexMetadata.keyspace()\n                                + "."\n                                + org.elassandra.cluster.SchemaManager.typeToCfName(updatedIndexMetadata.keyspace(), mergedMapper.type())\n                        );\n                    if (elasticSecondaryIndex != null) {\n                        elasticSecondaryIndex.updateMappingInfo(\n                            ClusterState.builder(currentState).metadata(builder.build()).build()\n                        );\n                    }\n                }\n                updated |= updatedMapping;\n"""

live_merge_schema_block = """                builder.put(indexMetadataBuilder);\n                IndexMetadata updatedIndexMetadata = builder.get(index.getName());\n                if (updatedMapping && MapperService.DEFAULT_MAPPING.equals(mergedMapper.type()) == false) {\n                    java.util.Map<String, Integer> replication = new java.util.LinkedHashMap<>();\n                    for (String entry : IndexMetadata.INDEX_SETTING_REPLICATION_SETTING.get(updatedIndexMetadata.getSettings())) {\n                        int colon = entry.indexOf(':');\n                        replication.put(entry.substring(0, colon), Integer.parseInt(entry.substring(colon + 1)));\n                    }\n                    org.apache.cassandra.schema.KeyspaceMetadata ksm = clusterService.getSchemaManager().createOrUpdateKeyspace(\n                        updatedIndexMetadata.keyspace(),\n                        updatedIndexMetadata.getNumberOfReplicas() + 1,\n                        replication,\n                        mutations,\n                        events\n                    );\n                    clusterService.getSchemaManager().updateTableSchema(\n                        ksm,\n                        mergedMapper.type(),\n                        java.util.Collections.singletonMap(\n                            updatedIndexMetadata.getIndex(),\n                            org.apache.cassandra.utils.Pair.create(updatedIndexMetadata, mapperService)\n                        ),\n                        mutations,\n                        events\n                    );\n                    if (mutations.isEmpty() == false) {\n                        org.apache.cassandra.schema.MigrationManager.mergeSchema(\n                            mutations,\n                            clusterService.getSchemaManager().getInhibitedSchemaListeners()\n                        );\n                    }\n                    org.opensearch.index.IndexService liveIndexService = indicesService.indexService(updatedIndexMetadata.getIndex());\n                    if (liveIndexService != null) {\n                        liveIndexService.mapperService().merge(updatedIndexMetadata, MergeReason.MAPPING_UPDATE);\n                    }\n                    org.elassandra.index.ElasticSecondaryIndex elasticSecondaryIndex =\n                        org.elassandra.index.ElasticSecondaryIndex.elasticSecondayIndices.get(\n                            updatedIndexMetadata.keyspace()\n                                + "."\n                                + org.elassandra.cluster.SchemaManager.typeToCfName(updatedIndexMetadata.keyspace(), mergedMapper.type())\n                        );\n                    if (elasticSecondaryIndex != null) {\n                        elasticSecondaryIndex.updateMappingInfo(\n                            ClusterState.builder(currentState).metadata(builder.build()).build()\n                        );\n                    }\n                }\n                updated |= updatedMapping;\n"""

snapshot_builder_schema_block = """                builder.put(indexMetadataBuilder);\n                IndexMetadata updatedIndexMetadata = builder.get(index.getName());\n                if (updatedMapping && MapperService.DEFAULT_MAPPING.equals(mergedMapper.type()) == false) {\n                    java.util.Map<String, Integer> replication = new java.util.LinkedHashMap<>();\n                    for (String entry : IndexMetadata.INDEX_SETTING_REPLICATION_SETTING.get(updatedIndexMetadata.getSettings())) {\n                        int colon = entry.indexOf(':');\n                        replication.put(entry.substring(0, colon), Integer.parseInt(entry.substring(colon + 1)));\n                    }\n                    org.apache.cassandra.schema.KeyspaceMetadata ksm = clusterService.getSchemaManager().createOrUpdateKeyspace(\n                        updatedIndexMetadata.keyspace(),\n                        updatedIndexMetadata.getNumberOfReplicas() + 1,\n                        replication,\n                        mutations,\n                        events\n                    );\n                    clusterService.getSchemaManager().updateTableSchema(\n                        ksm,\n                        mergedMapper.type(),\n                        java.util.Collections.singletonMap(\n                            updatedIndexMetadata.getIndex(),\n                            org.apache.cassandra.utils.Pair.create(updatedIndexMetadata, mapperService)\n                        ),\n                        mutations,\n                        events\n                    );\n                    if (mutations.isEmpty() == false) {\n                        org.apache.cassandra.schema.MigrationManager.mergeSchema(\n                            mutations,\n                            clusterService.getSchemaManager().getInhibitedSchemaListeners()\n                        );\n                    }\n                    org.opensearch.index.IndexService liveIndexService = indicesService.indexService(updatedIndexMetadata.getIndex());\n                    if (liveIndexService != null) {\n                        liveIndexService.mapperService().merge(updatedIndexMetadata, MergeReason.MAPPING_UPDATE);\n                    }\n                    org.elassandra.index.ElasticSecondaryIndex elasticSecondaryIndex =\n                        org.elassandra.index.ElasticSecondaryIndex.elasticSecondayIndices.get(\n                            updatedIndexMetadata.keyspace()\n                                + "."\n                                + org.elassandra.cluster.SchemaManager.typeToCfName(updatedIndexMetadata.keyspace(), mergedMapper.type())\n                        );\n                    if (elasticSecondaryIndex != null) {\n                        Metadata mappingMetadata = Metadata.builder(currentState.metadata()).put(indexMetadataBuilder).build();\n                        elasticSecondaryIndex.updateMappingInfo(\n                            ClusterState.builder(currentState).metadata(mappingMetadata).build()\n                        );\n                    }\n                }\n                updated |= updatedMapping;\n"""

schema_block_new = """                builder.put(indexMetadataBuilder);\n                IndexMetadata updatedIndexMetadata = builder.get(index.getName());\n                if (updatedMapping && MapperService.DEFAULT_MAPPING.equals(mergedMapper.type()) == false) {\n                    java.util.Map<String, Integer> replication = new java.util.LinkedHashMap<>();\n                    for (String entry : IndexMetadata.INDEX_SETTING_REPLICATION_SETTING.get(updatedIndexMetadata.getSettings())) {\n                        int colon = entry.indexOf(':');\n                        replication.put(entry.substring(0, colon), Integer.parseInt(entry.substring(colon + 1)));\n                    }\n                    org.apache.cassandra.schema.KeyspaceMetadata ksm = clusterService.getSchemaManager().createOrUpdateKeyspace(\n                        updatedIndexMetadata.keyspace(),\n                        updatedIndexMetadata.getNumberOfReplicas() + 1,\n                        replication,\n                        mutations,\n                        events\n                    );\n                    clusterService.getSchemaManager().updateTableSchema(\n                        ksm,\n                        mergedMapper.type(),\n                        java.util.Collections.singletonMap(\n                            updatedIndexMetadata.getIndex(),\n                            org.apache.cassandra.utils.Pair.create(updatedIndexMetadata, mapperService)\n                        ),\n                        mutations,\n                        events\n                    );\n                    if (mutations.isEmpty() == false) {\n                        org.apache.cassandra.schema.MigrationManager.mergeSchema(\n                            mutations,\n                            clusterService.getSchemaManager().getInhibitedSchemaListeners()\n                        );\n                    }\n                    org.opensearch.index.IndexService liveIndexService = indicesService.indexService(updatedIndexMetadata.getIndex());\n                    if (liveIndexService != null) {\n                        liveIndexService.mapperService().merge(updatedIndexMetadata, MergeReason.MAPPING_UPDATE);\n                    }\n                    org.elassandra.index.ElasticSecondaryIndex elasticSecondaryIndex =\n                        org.elassandra.index.ElasticSecondaryIndex.elasticSecondayIndices.get(\n                            updatedIndexMetadata.keyspace()\n                                + "."\n                                + org.elassandra.cluster.SchemaManager.typeToCfName(updatedIndexMetadata.keyspace(), mergedMapper.type())\n                        );\n                    if (elasticSecondaryIndex != null) {\n                        Metadata mappingMetadata = Metadata.builder(currentState.metadata()).put(updatedIndexMetadata, false).build();\n                        elasticSecondaryIndex.updateMappingInfo(\n                            ClusterState.builder(currentState).metadata(mappingMetadata).build()\n                        );\n                    }\n                }\n                updated |= updatedMapping;\n"""

submit_old = """            ClusterStateTaskConfig.build(Priority.HIGH, request.masterNodeTimeout()),\n"""
submit_new = """            ClusterStateTaskConfig.build(Priority.HIGH, request.masterNodeTimeout(), request.schemaUpdate()),\n"""

text = replace_once(text, execute_old, execute_new, "PutMappingExecutor.execute")
text = replace_once(text, signature_old, signature_new, "applyRequest signature")

if schema_block_new not in text:
    if patched_schema_block in text:
        text = text.replace(patched_schema_block, schema_block_new, 1)
    elif bridge_schema_block in text:
        text = text.replace(bridge_schema_block, schema_block_new, 1)
    elif live_merge_schema_block in text:
        text = text.replace(live_merge_schema_block, schema_block_new, 1)
    elif snapshot_builder_schema_block in text:
        text = text.replace(snapshot_builder_schema_block, schema_block_new, 1)
    elif current_schema_block in text:
        text = text.replace(current_schema_block, schema_block_new, 1)
    elif original_schema_block in text:
        text = text.replace(original_schema_block, schema_block_new, 1)
    else:
        raise SystemExit(f"{path}: anchor not found for schema block")

text = replace_once(text, submit_old, submit_new, "putMapping task config")

path.write_text(text, encoding="utf-8")
print("Patched MetadataMappingService schema-update flow:", path)
PY
